#include<bits/stdc++.h>
using namespace std;
int n,m,dp[2020][2020],h[2020];
char a[2020][2020];
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%s",a[i]+1);
    }
    for(int i=1;i<=m;i++)
    {
        for(int j=1;j<=n;j++)
        {
            if(a[j][i]=='#')
            {
                h[i]=n-j+1;
                break;
            }
        }
    }
    for(int i=0;i<=n+1;i++)
    {
        dp[0][i]=1;
    }
    for(int i=1;i<=m;i++)
    {
        for(int j=h[i];j<=n;j++)
        {
            dp[i][j]=dp[i-1][j+1];
        }
        for(int j=h[i]+1;j<=n+1;j++)
        {
            dp[i][j]=(dp[i][j-1]+dp[i][j])%998244353;
        }
    }
    printf("%d",dp[m][n+1]);
    return 0;
}
